Implementing optimized initialization and copy/move blocks:

```cpp
#include <string>

class UTexture {
public:
    std::string Name;
    UTexture(std::string InName) : Name(InName) {} // Parameterized with initializer list
};

class AMaterial {
private:
    UTexture* diffuseMap;

public:
    // Initializer list prevents double-initialization
    AMaterial(UTexture* InDiffuse) : diffuseMap(InDiffuse) {}

    // Copy Constructor - Deep copies the underlying texture
    AMaterial(const AMaterial& Other) {
        diffuseMap = new UTexture(Other.diffuseMap->Name);
    }

    ~AMaterial() {
        delete diffuseMap;
    }
};
```
